// T615 DeliveryGateEscrowController
// Release path
async releaseEscrow(event): Promise<DataProcessResult<unknown>> {
  // ORDER 1: Validate delivery gate
  const delivery = await this.db.searchDocuments('xiigen-deliveries', { milestoneId, status: 'SUBMITTED' });
  if (!delivery.data?.length) return DataProcessResult.failure('DELIVERY_NOT_SUBMITTED', ...);
  // ORDER 2: Release milestone funds
  await this.db.storeDocument('xiigen-milestones', { ...milestone, status: 'RELEASED' }, milestoneId);
  // ORDER 3: Audit (DNA-8)
  await this.db.storeDocument('xiigen-escrow-audit', { ... });
  // ORDER 4: Emit
  await this.queue.enqueue('MilestoneReleased', { milestoneId, releasedAt });
}

